INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'db66cdf0-bf94-4dd2-83fc-9bf649c5c0de',
  '00000000-0000-0000-0000-000000000001',
  $escape$Godot Multiplayer Foundation: Client-Server vs P2P with State Synchronization$escape$,
  $escape$Godot's built-in networking features support both client-server and peer-to-peer (P2P) architectures. When choosing between these, consider the game's requirements: client-server is more scalable, while P2P reduces latency. For state synchronization, Godot's RPC (Remote Procedure Call) system can be used to send and receive data between nodes. To implement rollback netcode, use Godot's built-in `Network` class to handle packet sending and receiving, and the `PhysicsServer` to simulate physics on the server-side.$escape$,
  $escape$extends NetworkedNode
func _ready():
    if get_tree().is_network_server():
        # Server-side code
        pass
    else:
        # Client-side code
        rpc_id(1, "sync_state", get_transform())$escape$,
  $escape$gdscript$escape$,
